def euler_deg_to_matrix(x, y, z, rz, ry, rx):
    t = np.array([x, y, z], dtype=np.float64) / 1000.0
    rx, ry, rz = np.deg2rad([rx, ry, rz])
    Rz = np.array([[np.cos(rz), -np.sin(rz), 0],
                   [np.sin(rz),  np.cos(rz), 0],
                   [0, 0, 1]])
    Ry = np.array([[np.cos(ry), 0, np.sin(ry)],
                   [0, 1, 0],
                   [-np.sin(ry), 0, np.cos(ry)]])
    Rx = np.array([[1, 0, 0],
                   [0, np.cos(rx), -np.sin(rx)],
                   [0, np.sin(rx),  np.cos(rx)]])
    R = Rz @ Ry @ Rx
    T = np.eye(4)
    T[:3, :3] = R
    T[:3, 3] = t
    return T

def compute_pose_error(T1, T2):
    pos1 = T1[:3, 3]
    pos2 = T2[:3, 3]
    position_error = np.linalg.norm(pos1 - pos2)

    R1 = T1[:3, :3]
    R2 = T2[:3, :3]
    R_err = R1.T @ R2
    angle_error = np.arccos(np.clip((np.trace(R_err) - 1) / 2.0, -1.0, 1.0))
    angle_error_deg = np.rad2deg(angle_error)
    return position_error, angle_error_deg

def average_transforms(T_list):
    positions = np.array([T[:3, 3] for T in T_list])
    avg_pos = np.mean(positions, axis=0)

    Rs = np.array([T[:3, :3] for T in T_list])
    R_avg = np.zeros((3, 3))
    for R in Rs:
        R_avg += R
    U, _, Vt = np.linalg.svd(R_avg)
    R_mean = U @ Vt

    T_avg = np.eye(4)
    T_avg[:3, :3] = R_mean
    T_avg[:3, 3] = avg_pos
    return T_avg

