robot_Ts_all = [euler_deg_to_matrix(*pose) for pose in robot_poses]
robot_Ts_all = np.array(robot_Ts_all)
np.save("robot_poses.npy", robot_Ts_all)
print("robot_poses.npy 저장 완료")

# Step 1.5: 유효한 index로 필터링
valid_indices = np.load("charuco_valid_indices.npy")
robot_Ts = robot_Ts_all[valid_indices]

# Step 2: charuco_poses 불러오기 (이미 유효한 index만 저장된 것)
charuco_Ts = np.load("charuco_poses_d.npy")
assert len(robot_Ts) == len(charuco_Ts), "pose 수가 맞지 않습니다!"

# Step 3: AX = XB 구성
R_gripper2base = []
t_gripper2base = []
R_target2cam = []
t_target2cam = []

for i in range(len(robot_Ts) - 1):
    A = np.linalg.inv(robot_Ts[i]) @ robot_Ts[i + 1]
    B = charuco_Ts[i + 1] @ np.linalg.inv(charuco_Ts[i])
    R_gripper2base.append(A[:3, :3])
    t_gripper2base.append(A[:3, 3])
    R_target2cam.append(B[:3, :3])
    t_target2cam.append(B[:3, 3])

# Step 4: solve AX = XB using OpenCV
R_gc, t_gc = cv2.calibrateHandEye(
    R_gripper2base, t_gripper2base,
    R_target2cam, t_target2cam,
    method=cv2.CALIB_HAND_EYE_PARK
)

# Step 5: 결과 행렬 저장
T_gc = np.eye(4)
T_gc[:3, :3] = R_gc
T_gc[:3, 3] = t_gc.flatten()
np.save("gTc_handeye_CG2_1111.npy", T_gc)
print("저장 완료: gTc_handeye_robotiq.npy")
print("\n===Hand–Eye Calibration Result (gTc) ===")
print(T_gc)

# === 회전 행렬 검증 ===
R = T_gc[:3, :3]
t = T_gc[:3, 3]
print("R.T @ R:\n", R.T @ R)
print("det(R):", np.linalg.det(R))
print("\n=== Translation 검증 ===")
print("t vector:", t)
print("‣ X: {:.2f} cm".format(t[0]*100))
print("‣ Y: {:.2f} cm".format(t[1]*100))
print("‣ Z: {:.2f} cm".format(t[2]*100))
print("‣ 전체 거리: {:.2f} cm".format(np.linalg.norm(t)*100))

# === 여러 프레임에서 board pose 평균 ===
T_bTt_list = [ (robot_Ts[i] @ T_gc) @ charuco_Ts[i] for i in range(len(robot_Ts)) ]
T_bTt = average_transforms(T_bTt_list)

# === Pose 검증 (bTg * gTc ≈ bTt * tTc) ===
print("\n=== Pose 검증 (bTg * gTc ≈ bTt * tTc) ===")
total_pos_err = 0
total_rot_err = 0

for i in range(len(robot_Ts)):
    T_bTg = robot_Ts[i]
    T_cTt = charuco_Ts[i]

    T_bTc_est = T_bTg @ T_gc
    T_bTc_gt = T_bTt @ np.linalg.inv(T_cTt)

    pos_err, rot_err = compute_pose_error(T_bTc_est, T_bTc_gt)
    total_pos_err += pos_err
    total_rot_err += rot_err

    print(f"[{i}] 위치 오차: {pos_err*1000:.2f} mm, 회전 오차: {rot_err:.2f} deg")

print("\n=== 평균 오차 ===")
print("위치 오차: {:.2f} mm".format((total_pos_err / len(robot_Ts)) * 1000))
print("회전 오차: {:.2f} deg".format(total_rot_err / len(robot_Ts)))

# === 시각화 ===
def draw_frame(ax, T, label, length=0.1):
    origin = T[:3, 3]
    x_axis = T[:3, 0] * length
    y_axis = T[:3, 1] * length
    z_axis = T[:3, 2] * length
    ax.quiver(*origin, *x_axis, color='r')
    ax.quiver(*origin, *y_axis, color='g')
    ax.quiver(*origin, *z_axis, color='b')
    ax.text(*origin, label, fontsize=9)

T_base = np.eye(4)
T_ee = robot_Ts[0]
T_cam = T_ee @ T_gc
T_board = T_bTt

fig = plt.figure()
ax = fig.add_subplot(111, projection='3d')
draw_frame(ax, T_base, 'Base')
draw_frame(ax, T_ee, 'EE')
draw_frame(ax, T_cam, 'Cam')
draw_frame(ax, T_board, 'Board')

ax.set_xlim([-0.5, 0.5])
ax.set_ylim([-0.5, 0.5])
ax.set_zlim([0.0, 1.0])
ax.set_xlabel('X (m)')
ax.set_ylabel('Y (m)')
ax.set_zlabel('Z (m)')
ax.set_title("Base, EE, Camera, and Board Frames")
plt.tight_layout()
plt.show()

